// Determine the correct Notion status from Prosp campaign status
// and ensure we never downgrade an existing contact's status
const STATUS_PRIORITY = {
  'Connection Sent': 1,
  'Connection Accepted': 2,
  'Loom Sent': 3,
  'Follow-Up Sequence': 4,
  'Responded': 5,
  'Pending Approval': 6,
  'Meeting Booked': 7,
  'Meeting Held': 8,
  'Proposal Sent': 9,
  'Contract Sent': 10,
  'Project Started': 11,
  'Declined': 0
};

const existingContact = $('Find Existing Contact').first().json.results[0];
const currentStatus = existingContact?.properties?.Status?.select?.name || '';
const currentPriority = STATUS_PRIORITY[currentStatus] || 0;

const campaignStatus = $('Loop (1 at a time)').first().json.campaign_status || '';

// Map Prosp status to Notion status
let newStatus = 'Connection Sent';
let setAccepted = false;
let setResponded = false;

if (campaignStatus.includes('replied') || campaignStatus.includes('response') || campaignStatus.includes('responded')) {
  newStatus = 'Responded';
  setAccepted = true;
  setResponded = true;
} else if (campaignStatus.includes('accepted') || campaignStatus.includes('connected')) {
  newStatus = 'Connection Accepted';
  setAccepted = true;
} else if (campaignStatus.includes('pending') || campaignStatus.includes('sent') || campaignStatus.includes('invited')) {
  newStatus = 'Connection Sent';
}

const newPriority = STATUS_PRIORITY[newStatus] || 0;

// Only advance status forward, never downgrade
const shouldUpdateStatus = newPriority > currentPriority;

return [{
  json: {
    notion_page_id: existingContact.id,
    current_status: currentStatus,
    new_status: shouldUpdateStatus ? newStatus : currentStatus,
    should_update_status: shouldUpdateStatus,
    set_accepted: setAccepted,
    set_responded: setResponded,
    full_name: $('Loop (1 at a time)').first().json.full_name,
    email: $('Loop (1 at a time)').first().json.email,
    company: $('Loop (1 at a time)').first().json.company,
    title: $('Loop (1 at a time)').first().json.title,
    linkedin_url: $('Loop (1 at a time)').first().json.linkedin_url
  }
}];

