// Build the Notion status and checkboxes for a new contact
const item = $('Loop (1 at a time)').first().json;
const campaignStatus = item.campaign_status || '';

let status = 'Connection Sent';
let liAccepted = false;
let responded = false;

if (campaignStatus.includes('replied') || campaignStatus.includes('response') || campaignStatus.includes('responded')) {
  status = 'Responded';
  liAccepted = true;
  responded = true;
} else if (campaignStatus.includes('accepted') || campaignStatus.includes('connected')) {
  status = 'Connection Accepted';
  liAccepted = true;
} else {
  status = 'Connection Sent';
}

return [{
  json: {
    full_name: item.full_name,
    email: item.email,
    linkedin_url: item.linkedin_url,
    company: item.company,
    title: item.title,
    status: status,
    li_accepted: liAccepted,
    responded: responded
  }
}];

